class STSAssumeRoleCredentialsProvider(
  roleArn: String,
  sessionName: String,
  region: Region,
  baseProvider: CredentialsProvider
) extends CredentialsProvider {
  override def getCredentials: AwsCredentialsProvider = {
    val stsClient = StsClient.builder()
      .region(region)
      .credentialsProvider(baseProvider.getCredentials)
      .build()

    StsAssumeRoleCredentialsProvider.builder()
      .stsClient(stsClient)
      .refreshRequest(
        AssumeRoleRequest.builder()
          .roleArn(roleArn)
          .roleSessionName(sessionName)
          .build()
      )
      .build()
  }
}

class ChainedCredentialsProvider(providers: Seq[CredentialsProvider]) extends CredentialsProvider {
  override def getCredentials: AwsCredentialsProvider = {
    AwsCredentialsProviderChain.builder()
      .credentialsProviders(providers.map(_.getCredentials).asJava)
      .build()
  }
}

