object AWSServiceManager {
  
  def withDefaultCredentials(region: Region): AWSServiceManager = {
    val credentialsProvider = new ChainedCredentialsProvider(Seq(
      new EnvironmentCredentialsProvider(),
      new SystemPropertyCredentialsProvider(),
      new ProfileCredentialsProvider("default"),
      new WebIdentityTokenCredentialsProvider(),
      new ContainerCredentialsProvider(),
      new InstanceProfileCredentialsProvider()
    ))
    
    val config = AWSConfig(region, credentialsProvider)
    new AWSServiceManager(config)
  }

  def withProfile(region: Region, profileName: String): AWSServiceManager = {
    val credentialsProvider = new ProfileCredentialsProvider(profileName)
    val config = AWSConfig(region, credentialsProvider)
    new AWSServiceManager(config)
  }

  def withEnvironmentCredentials(region: Region): AWSServiceManager = {
    val credentialsProvider = new EnvironmentCredentialsProvider()
    val config = AWSConfig(region, credentialsProvider)
    new AWSServiceManager(config)
  }

  def withAssumeRole(
    region: Region,
    roleArn: String,
    sessionName: String,
    baseProvider: CredentialsProvider = new DefaultCredentialsProvider()
  ): AWSServiceManager = {
    val credentialsProvider = new STSAssumeRoleCredentialsProvider(
      roleArn,
      sessionName,
      region,
      baseProvider
    )
    val config = AWSConfig(region, credentialsProvider)
    new AWSServiceManager(config)
  }
}

object AWSServiceExample {
  def main(args: Array[String]): Unit = {
    val manager = AWSServiceManager.withDefaultCredentials(Region.US_EAST_1)

    manager.s3Service.listBuckets() match {
      case Success(buckets) => 
        println(s"Buckets: ${buckets.mkString(", ")}")
      case Failure(exception) => 
        println(s"Error listing buckets: ${exception.getMessage}")
    }

    manager.sqsService.createQueue("my-queue") match {
      case Success(queueUrl) => 
        println(s"Queue created: $queueUrl")
        manager.sqsService.sendMessage(queueUrl, "Hello from Scala!")
      case Failure(exception) => 
        println(s"Error creating queue: ${exception.getMessage}")
    }

    manager.secretsManagerService.getSecretValue("my-secret") match {
      case Success(secret) => 
        println(s"Retrieved secret successfully")
      case Failure(exception) => 
        println(s"Error retrieving secret: ${exception.getMessage}")
    }

    manager.closeAll()
  }
}